class Solution:
    def mergeKLists(self, lists):
        if not lists:
            return None

        def go(l, r):
            if l == r:
                return lists[l]
            m = (l + r) // 2
            return _merge2(go(l, m), go(m + 1, r))

        return go(0, len(lists) - 1)

