import heapq                          # 堆(优先队列):每次 O(log) 取最小

class Solution:
    def mergeKLists(self, lists):
        h: list = []
        for i, head in enumerate(lists):
            if head:
                heapq.heappush(h, (head.val, i, head))  # 元组先比 val;i 用来打破 val 相等
        dummy = ListNode()
        t = dummy
        while h:
            v, i, node = heapq.heappop(h)   # 弹出当前最小结点
            t.next = node
            t = t.next
            if node.next:                   # 该链还有下一个 -> 入堆
                heapq.heappush(h, (node.next.val, i, node.next))
        return dummy.next
